body.script:
//
(function() {
  'use strict';

  /* ── State ─────────────────────────────────────────────── */
  var currentPlayerId = null;
  var currentPlayerName = '';
  var currentPlayerState = '';
  var currentPlayerPhoto = '';
  var currentPlayerSerial = '';
  var currentPlayerTierName = '';
  var currentPlayerTierColor = '#3498db';
  var smSelectedTeam = null;
  var smTeamsData = [];
  var smSoldTimer = null;
  var smPlayerIdForSell = null;

  /* ── RPC helper ────────────────────────────────────────── */
  function rpc(url, params) {
    return fetch(url, {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({jsonrpc: '2.0', method: 'call', params: params})
    }).then(function(r) { return r.json(); });
  }

  function callKw(model, method, args, kwargs) {
    return rpc('/web/dataset/call_kw', {
      model: model, method: method, args: args, kwargs: kwargs || {}
    });
  }

  /* ── Grid ──────────────────────────────────────────────── */
  function loadGrid() {
    rpc('/auction/get_players_queue', {}).then(function(res) {
      var players = res.result || [];
      var grid   = document.getElementById('auction_grid');
      var empty  = document.getElementById('mq_empty');
      var badge  = document.getElementById('gBadge');
      var sStat  = document.getElementById('sStat');
      var rStat  = document.getElementById('rStat');
      var sdStat = document.getElementById('soldStat');
      if (!grid) return;
      grid.innerHTML = '';
      if (!players.length) {
        if (empty) empty.style.display = 'block';
        if (badge) badge.textContent = '0 players';
        if (sStat) sStat.textContent = '0';
        if (rStat) rStat.textContent = '0';
        if (sdStat) sdStat.textContent = '0';
        return;
      }
      if (empty) empty.style.display = 'none';
      var soldCount = 0, unsoldCount = 0;
      players.forEach(function(p) {
      var btn = document.createElement('button');
        btn.type = 'button';
        btn.className = 'mq-btn';
        btn.dataset.id = p.id;
        var numSpan = document.createElement('span');
        numSpan.className = 'mq-num';
        numSpan.textContent = p.serial;
        btn.appendChild(numSpan);
        if (p.state === 'sold') {
          btn.classList.add('sold');
          soldCount++;
          var lbl = document.createElement('span');
          lbl.className = 'mq-lbl';
          lbl.textContent = '✔ SOLD';
          btn.appendChild(lbl);
        } else if (p.state === 'unsold') {
          btn.classList.add('unsold');
          unsoldCount++;
          var lbl = document.createElement('span');
          lbl.className = 'mq-lbl';
          lbl.textContent = '✖ UNSOLD';
          btn.appendChild(lbl);
        }
        btn.onclick = function() { openPlayerDrawer(p.id); };
        grid.appendChild(btn);
      });
      var total     = players.length;
      var remaining = total - soldCount - unsoldCount;
      if (badge)  badge.textContent  = total + ' player' + (total !== 1 ? 's' : '');
      if (sStat)  sStat.textContent  = total;
      if (rStat)  rStat.textContent  = remaining;
      if (sdStat) sdStat.textContent = soldCount;
    }).catch(function(e) { console.error('loadGrid:', e); });
  }

  /* ── Footer ticker ──────────────────────────────────────── */
  function loadTicker() {
    callKw('auction.auction', 'search_read', [], {
      domain: [],
      fields: ['team_id', 'remaining_points', 'max_call', 'remaining_players_count']
    }).then(function(res) {
      var teams = res.result || [];
      var track = document.getElementById('tickerTrack');
      if (!track) return;
      if (!teams.length) {
        track.innerHTML = '<span class="mq-ticker-no-data">No team data</span>';
        track.style.animation = 'none';
        return;
      }
      var html = '';
      /* Double items for seamless infinite loop */
      for (var loop = 0; loop < 2; loop++) {
        teams.forEach(function(t) {
          var teamName = t.team_id ? t.team_id[1] : '—';
          html +=
            '<div class="mq-ticker-item">' +
            '<span class="mq-ticker-team">' + escHtml(teamName) + '</span>' +
            '<span class="mq-ticker-dot"></span>' +
            '<span class="mq-ticker-purse">&#x1F4B0; ' + t.remaining_points + ' pts</span>' +
            '<span class="mq-ticker-max">Max: ' + t.max_call + '</span>' +
            '</div>';
        });
      }
      track.innerHTML = html;
      var duration = Math.max(12, teams.length * 4);
      track.style.animation = 'tickerMove ' + duration + 's linear infinite';
    }).catch(function() {});
  }

  /* ── Player Drawer ─────────────────────────────────────── */
  window.openPlayerDrawer = function(playerId) {
    currentPlayerId = playerId;
    var overlay = document.getElementById('playerDrawer');
    var body    = document.getElementById('pcBody');
    var actions = document.getElementById('pcActions');
    if (body) body.innerHTML = '<div class="pc-loading">Loading player&#8230;</div>';
    if (actions) actions.style.display = 'none';
    overlay.classList.add('open');
    document.body.style.overflow = 'hidden';

    callKw('auction.team.player', 'read',
      [[playerId], ['sl_no', 'name', 'role', 'batting_style', 'bowling_style', 'photo', 'tier_id', 'tier_color', 'state', 'contact']]
    ).then(function(res) {
      var p = (res.result || [])[0];
      if (!p) { if (body) body.innerHTML = '<div class="pc-loading">Player not found.</div>'; return; }
      currentPlayerName      = p.name || '';
      currentPlayerState     = p.state || '';
      currentPlayerPhoto     = p.photo || '';
      currentPlayerSerial    = p.sl_no || '';
      currentPlayerTierName  = p.tier_id ? p.tier_id[1] : '';
      currentPlayerTierColor = p.tier_color || '#3498db';
      renderPlayerCard(p, body);
      if (actions) {
        actions.style.display = p.state === 'sold' || p.state === 'unsold' ? 'none' : 'flex';
      }
      /* Sync live board: mark this player as on-stage */
      callKw('auction.team.player', 'action_set_on_stage', [[playerId]]).catch(function(){});
    }).catch(function() {
      if (body) body.innerHTML = '<div class="pc-loading">Error loading player.</div>';
    });
  };

  window.closePlayerDrawer = function(keepOnStage) {
    var overlay = document.getElementById('playerDrawer');
    overlay.classList.remove('open');
    document.body.style.overflow = '';
    /* Clear on-stage only when dismissed without action; sold/unsold pass keepOnStage=true */
    if (!keepOnStage && currentPlayerId) {
      callKw('auction.team.player', 'write', [[currentPlayerId], {'is_on_stage': false}]).catch(function(){});
    }
    currentPlayerId = null;
    setTimeout(loadGrid,   300);
    setTimeout(loadTicker, 350);
  };

  window.handlePCBackdropClick = function(e) {
    if (e.target.classList.contains('pc-backdrop') || e.target === document.getElementById('playerDrawer')) {
      closePlayerDrawer();
    }
  };

  function renderPlayerCard(p, container) {
    var photo = '';
    if (p.photo) {
      photo = '<img class="pc-photo" src="data:image/png;base64,' + p.photo + '" alt="' + escHtml(p.name) + '"/>';
    } else {
      photo = '<div class="pc-photo-ph">&#128100;</div>';
    }
    var tierColor  = p.tier_color || '#3498db';
    var tierGlow   = tierColor + '55'; /* 33% alpha glow */
    var tier = p.tier_id
      ? '<span class="pc-tier-badge" style="background:' + escHtml(tierColor) + ';color:#fff;box-shadow:0 0 12px ' + escHtml(tierGlow) + '">'
          + escHtml(p.tier_id[1]) + '</span>'
      : '';
    var stateBanner = '';
    if (p.state === 'sold')   stateBanner = '<div class="pc-state-banner sold">&#10003; Sold</div>';
    if (p.state === 'unsold') stateBanner = '<div class="pc-state-banner unsold">&#10005; Unsold</div>';

    container.innerHTML =
      '<div class="pc-photo-wrap" id="pcPhotoWrap" style="border-left:4px solid ' + escHtml(tierColor) + ';box-shadow:inset -200px 0 120px -80px ' + escHtml(tierGlow) + '">' + photo + '</div>' +
      '<div class="pc-info">' +
        '<div class="pc-serial" style="color:' + escHtml(tierColor) + ';text-shadow:0 0 24px ' + escHtml(tierGlow) + '">#' + escHtml(String(p.sl_no)) + '</div>' +
        '<div class="pc-name">' + escHtml(p.name) + '</div>' +
        tier +
        '<div class="pc-attrs">' +
          attr('Role', p.role || '—') +
          attr('Batting', p.batting_style || '—') +
          attr('Bowling', p.bowling_style || '—') +
          attr('Contact', p.contact || '—') +
        '</div>' +
        stateBanner +
      '</div>';
  }

  function attr(label, val) {
    return '<div class="pc-attr">' +
      '<div class="pc-attr-label">' + escHtml(label) + '</div>' +
      '<div class="pc-attr-val">' + escHtml(val) + '</div>' +
      '</div>';
  }

  function escHtml(s) {
    return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  }

  /* ── Unsold flow ───────────────────────────────────────── */
  window.openUnsoldConfirm = function() {
    var sub = document.getElementById('cmSub');
    if (sub) sub.textContent = 'Mark "' + currentPlayerName + '" as unsold?';
    document.getElementById('unsoldModal').classList.add('open');
  };

  window.closeUnsoldConfirm = function() {
    document.getElementById('unsoldModal').classList.remove('open');
  };

  window.doUnsold = function() {
    closeUnsoldConfirm();
    if (!currentPlayerId) return;
    callKw('auction.team.player', 'action_unsold', [[currentPlayerId]]).then(function(res) {
      var result = res.result || {};
      var secs   = result.display_seconds > 0 ? result.display_seconds : 5;
      showStamp('UNSOLD', secs, function() { closePlayerDrawer(true); });
    }).catch(function() { closePlayerDrawer(); });
  };

  /* ── Sell flow ─────────────────────────────────────────── */
  window.openSellModal = function() {
    if (!currentPlayerId) return;
    smPlayerIdForSell = currentPlayerId;
    smSelectedTeam    = null;
    smTeamsData       = [];
    var nm = document.getElementById('smPlayerName');
    if (nm) nm.textContent = currentPlayerName;
    /* reset form */
    document.getElementById('smTeams').innerHTML = '<span class="sm-no-teams">Loading teams\u2026</span>';
    document.getElementById('smTeamDetail').classList.remove('show');
    document.getElementById('smSug').classList.remove('show');
    document.getElementById('smPoints').value = 0;
    document.getElementById('smPresets').innerHTML = '';
    smShowError('');
    var sellBtn = document.getElementById('smSellBtn');
    if (sellBtn) { sellBtn.disabled = true; sellBtn.textContent = 'Sell Player'; }
    document.getElementById('smForm').style.display = 'block';
    document.getElementById('smSoldScreen').classList.remove('show');
    document.getElementById('sellModal').classList.add('open');
    smLoadTeams();
  };

  window.closeSellModal = function() {
    if (smSoldTimer) { clearInterval(smSoldTimer); smSoldTimer = null; }
    document.getElementById('sellModal').classList.remove('open');
  };

  function smLoadTeams() {
    callKw('auction.team.player', 'get_sell_teams_data', [smPlayerIdForSell]).then(function(res) {
      smTeamsData = res.result || [];
      smRenderTeams(smTeamsData);
    }).catch(function() {
      document.getElementById('smTeams').innerHTML = '<span class="sm-no-teams">Network error loading teams.</span>';
    });
  }

  function smRenderTeams(teams) {
    var container = document.getElementById('smTeams');
    if (!teams.length) {
      container.innerHTML = '<span class="sm-no-teams">No teams available.</span>';
      return;
    }
    container.innerHTML = '';
    teams.forEach(function(t) {
      var disabled = !t.tier_slots_ok || !t.budget_ok;
      var btn = document.createElement('button');
      btn.className = 'sm-team-btn' + (disabled ? ' tier-full' : '');
      btn.textContent = t.team_name;
      btn.dataset.teamId = t.team_id;
      btn.disabled = disabled;
      if (disabled) {
        btn.title = !t.tier_slots_ok ? 'Tier slot full' : 'Insufficient budget';
      } else {
        btn.onclick = function() { smSelectTeam(t); };
      }
      container.appendChild(btn);
    });
  }

  function smSelectTeam(team) {
    smSelectedTeam = team;
    document.querySelectorAll('.sm-team-btn').forEach(function(b) {
      b.classList.toggle('active', b.dataset.teamId == team.team_id);
    });
    /* details strip */
    document.getElementById('smRemPts').textContent     = team.remaining_points;
    document.getElementById('smRemPlayers').textContent  = team.remaining_players;
    document.getElementById('smMaxCall').textContent     = team.max_call;
    document.getElementById('smTeamDetail').classList.add('show');
    /* suggestion */
    var sug = document.getElementById('smSug');
    sug.innerHTML = team.remaining_players > 1
      ? '\u2139 Max bid <strong>' + team.max_call + ' pts</strong> | Base for remaining: <strong>' + team.effective_base_point + ' pts</strong>'
      : '\u2139 Last slot! Max bid: <strong>' + team.max_call + ' pts</strong>';
    sug.classList.add('show');
    /* points */
    var inp = document.getElementById('smPoints');
    inp.value = team.effective_base_point;
    inp.min   = team.effective_base_point;
    inp.max   = team.max_call;
    smRenderPresets(team);
    smShowError('');
    var sellBtn = document.getElementById('smSellBtn');
    if (sellBtn) sellBtn.disabled = false;
  }

  function smRenderPresets(team) {
    var container = document.getElementById('smPresets');
    container.innerHTML = '';
    var presets = [];
    var base = team.effective_base_point;
    var max  = team.max_call;

    if (team.preset_points && team.preset_points.length > 0) {
      /* Use explicit tournament preset_points — filter to valid range, always include base & max */
      presets = team.preset_points.filter(function(v) { return v >= base && v <= max; });
      if (!presets.length || presets[0] !== base) presets.unshift(base);
      if (presets[presets.length - 1] !== max) presets.push(max);
    } else if (team.slabs && team.slabs.length > 0) {
      /* Generate from tournament slabs */
      var inc = smGetInc(base, team.slabs);
      for (var v = base; v <= max && presets.length < 8; v += inc) {
        presets.push(v);
        inc = smGetInc(v, team.slabs);
      }
      if (!presets.length || presets[presets.length - 1] !== max) presets.push(max);
    } else {
      /* No config at all — just show base and max */
      presets = [base];
      if (base !== max) presets.push(max);
    }

    presets.forEach(function(val) {
      var btn = document.createElement('button');
      btn.className = 'sm-preset';
      btn.textContent = val;
      btn.type = 'button';
      btn.onclick = function() {
        document.getElementById('smPoints').value = val;
        document.querySelectorAll('.sm-preset').forEach(function(b) { b.classList.remove('active'); });
        btn.classList.add('active');
      };
      container.appendChild(btn);
    });
  }

  window.adjPts = function(dir) {
    if (!smSelectedTeam) return;
    var inp     = document.getElementById('smPoints');
    var current = parseInt(inp.value) || smSelectedTeam.effective_base_point;
    var inc     = smGetInc(current, smSelectedTeam.slabs);
    var next    = Math.min(Math.max(current + dir * inc, smSelectedTeam.effective_base_point), smSelectedTeam.max_call);
    inp.value   = next;
    smShowError('');
  };

  function smGetInc(amount, slabs) {
    if (!slabs || !slabs.length) return 50;
    for (var i = 0; i < slabs.length; i++) {
      if (amount >= slabs[i].from_amount && amount <= slabs[i].to_amount) return slabs[i].increment;
    }
    return slabs[slabs.length - 1].increment || 50;
  }

  function smShowError(msg) {
    var el = document.getElementById('smError');
    if (!el) return;
    el.textContent = msg;
    el.classList.toggle('show', !!msg);
  }

  window.doSell = function() {
    if (!smSelectedTeam || !smPlayerIdForSell) return;
    var finalPts = parseInt(document.getElementById('smPoints').value);
    if (isNaN(finalPts) || finalPts <= 0) { smShowError('Please enter valid points.'); return; }
    var btn = document.getElementById('smSellBtn');
    if (btn) { btn.disabled = true; btn.textContent = 'Selling\u2026'; }
    smShowError('');
    callKw('auction.team.player', 'action_sell_from_web',
           [smPlayerIdForSell, smSelectedTeam.team_id, finalPts]).then(function(res) {
      var data = res.result;
      if (!data || !data.success) {
        smShowError(data ? data.error : 'Sell failed. Please try again.');
        if (btn) { btn.disabled = false; btn.textContent = 'Sell Player'; }
        return;
      }
      smShowSoldScreen(data);
    }).catch(function() {
      smShowError('Network error. Please try again.');
      if (btn) { btn.disabled = false; btn.textContent = 'Sell Player'; }
    });
  };

  function smShowSoldScreen(data) {
    var secs = data.display_seconds > 0 ? data.display_seconds : 5;
    closeSellModal();
    var subText = 'Sold to \u00a0' + data.team_name + '\u00a0 for \u00a0' + data.final_point + ' pts';
    showStamp('SOLD', secs, subText, function() { closePlayerDrawer(true); });
  }

  /* ── Full-screen stamp overlay ─────────────────────────── */
  function showStamp(text, secs, subText, onDone) {
    /* Support legacy 3-arg call: showStamp(text, secs, onDone) */
    if (typeof subText === 'function') { onDone = subText; subText = ''; }

    var cs = getComputedStyle(document.documentElement);
    var bg = text === 'UNSOLD'
      ? (cs.getPropertyValue('--unsold-bg').trim() || '#DC143C')
      : (cs.getPropertyValue('--sold-bg').trim()   || '#E8A020');
    var tx = text === 'UNSOLD'
      ? (cs.getPropertyValue('--unsold-tx').trim() || '#fff')
      : (cs.getPropertyValue('--sold-tx').trim()   || '#000');

    /* Player photo */
    var photoEl = document.getElementById('ssPhotoEl');
    if (photoEl) {
      photoEl.innerHTML = currentPlayerPhoto
        ? '<img class="ss-photo" src="data:image/png;base64,' + currentPlayerPhoto
            + '" alt="player" style="border:3px solid ' + currentPlayerTierColor + '"/>'
        : '<div class="ss-photo-ph">&#128100;</div>';
    }

    /* Stamp label */
    var stampEl = document.getElementById('ssStampText');
    if (stampEl) {
      stampEl.textContent = text;
      stampEl.style.cssText = 'background:' + bg + ';color:' + tx
        + ';box-shadow:0 0 0 3px ' + bg + ',0 8px 40px rgba(0,0,0,.5)';
      /* Restart animation */
      stampEl.style.animation = 'none';
      void stampEl.offsetHeight;
      stampEl.style.animation = '';
    }

    /* Serial & name */
    var serialEl = document.getElementById('ssSerial');
    if (serialEl) { serialEl.textContent = '#' + currentPlayerSerial; serialEl.style.color = currentPlayerTierColor; }
    var nameEl = document.getElementById('ssName');
    if (nameEl) nameEl.textContent = currentPlayerName;

    /* Tier badge */
    var badgeEl = document.getElementById('ssTierBadge');
    if (badgeEl) {
      if (currentPlayerTierName) {
        badgeEl.textContent = currentPlayerTierName;
        badgeEl.style.background = currentPlayerTierColor;
        badgeEl.style.display = 'inline-block';
      } else {
        badgeEl.style.display = 'none';
      }
    }

    /* Sub-text (e.g. "Sold to TeamX for 500 pts") */
    var subEl = document.getElementById('ssSub');
    if (subEl) { subEl.textContent = subText || ''; subEl.style.color = bg; }

    /* Progress bar */
    var bar = document.getElementById('ssBar');
    if (bar) {
      bar.style.background = bg;
      bar.style.transition = 'none';
      bar.style.width = '100%';
    }

    /* Show overlay (dismiss on click) */
    var screen = document.getElementById('stampScreen');
    screen.classList.add('show');
    screen.onclick = function() {
      screen.classList.remove('show');
      screen.onclick = null;
      if (onDone) onDone();
    };

    if (bar) {
      requestAnimationFrame(function() {
        requestAnimationFrame(function() {
          bar.style.transition = 'width ' + secs + 's linear';
          bar.style.width = '0%';
        });
      });
    }

    setTimeout(function() {
      screen.classList.remove('show');
      screen.onclick = null;
      if (onDone) onDone();
    }, secs * 1000);
  }

  /* ── Bid Summary ───────────────────────────────────────── */
  window.openBidSummary = function() {
    var iframe = document.getElementById('bsIframe');
    if (iframe && iframe.src === 'about:blank') {
      iframe.src = '/auction/show/team/balance';
    }
    document.getElementById('bsDrawer').classList.add('open');
    document.body.style.overflow = 'hidden';
  };

  window.closeBidSummary = function() {
    document.getElementById('bsDrawer').classList.remove('open');
    document.body.style.overflow = '';
  };

  window.handleBSBackdropClick = function(e) {
    if (e.target.classList.contains('bs-backdrop') || e.target === document.getElementById('bsDrawer')) {
      closeBidSummary();
    }
  };

  /* ── Fullscreen ────────────────────────────────────────── */
  window.toggleFS = function() {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(function() {});
    } else {
      document.exitFullscreen().catch(function() {});
    }
  };
  document.addEventListener('fullscreenchange', function() {
    var btn = document.getElementById('fsBtn');
    if (btn) btn.textContent = document.fullscreenElement ? '\u2715' : '\u26F6';
  });

  /* ── Keyboard close ────────────────────────────────────── */
  document.addEventListener('keydown', function(e) {
    if (e.key !== 'Escape') return;
    if (document.getElementById('sellModal').classList.contains('open')) { closeSellModal(); return; }
    if (document.getElementById('unsoldModal').classList.contains('open')) { closeUnsoldConfirm(); return; }
    if (document.getElementById('playerDrawer').classList.contains('open')) { closePlayerDrawer(); return; }
    if (document.getElementById('bsDrawer').classList.contains('open')) { closeBidSummary(); }
  });

  /* ── Init ──────────────────────────────────────────────── */
  window._auctionReloadGrid = loadGrid;
  document.addEventListener('DOMContentLoaded', function() {
    setTimeout(loadGrid,   100);
    setTimeout(loadTicker, 200);
  });
})();
//
